aws_tgw_site.minimal_config:
resource "xcsh_aws_tgw_site" "example" {
  name      = "example-aws-tgw-site"
  namespace = "staging"

  labels = {
    environment = "production"
    managed_by  = "terraform"
  }

  annotations = {
    "owner" = "platform-team"
  }

  aws_region = "us-west-2"

  aws_cred {
    name      = "aws-credentials"
    namespace = "staging"
  }

  vpc {
    new_vpc {
      name_tag     = "xcsh-tgw-vpc"
      primary_ipv4 = "10.0.0.0/16"
    }
  }

  tgw {
    new_tgw {
      name = "xcsh-tgw"
    }
  }

  instance_type = "t3.xlarge"

  services_vpc {
    aws_certified_hw = "aws-byol-voltmesh"
    az_nodes {
      aws_az_name = "us-west-2a"
      inside_subnet {
        subnet_param {
          ipv4 = "10.0.1.0/24"
        }
      }
      outside_subnet {
        subnet_param {
          ipv4 = "10.0.2.0/24"
        }
      }
      workload_subnet {
        subnet_param {
          ipv4 = "10.0.3.0/24"
        }
      }
    }
  }

  no_worker_nodes {}
}

